using Microsoft.AspNetCore.Mvc; using SchoolEnterprise.Helpers; using SchoolEnterprise.Models.Domain; using SchoolEnterprise.Repositories; using SchoolEnterprise.Services;
namespace SchoolEnterprise.Controllers; [RoleGuard("Admin")] public class UsersController(UserRepository repo, SequenceService seq):Controller{ public IActionResult Index()=>View(repo.GetAll()); [HttpGet] public IActionResult Create()=>View(); [HttpPost] public IActionResult Create(AppUser u){u.UserId=seq.Next("UserId"); repo.Add(u); return RedirectToAction(nameof(Index));} [HttpGet] public IActionResult Edit(int id)=>View(repo.GetById(id)); [HttpPost] public IActionResult Edit(AppUser u){repo.Update(u); return RedirectToAction(nameof(Index));} public IActionResult Delete(int id){repo.Delete(id); return RedirectToAction(nameof(Index));}}
